		} else {
			$wpdb->query( $wpdb->prepare(
				"UPDATE {$t} SET name = %s, energy_kcal = 135, energy_kj = 565, protein_g = 1.5, carbohydrate_g = 15.0, of_which_sugars_g = 8.0, fat_g = 8.0, of_which_saturates_g = 1.0, fibre_g = 1.5, salt_g = 4.0, iron_mg = 0.16, calcium_mg = 11.0, vitamin_c_mg = 36.4, is_active = 1 WHERE slug = %s AND (name = '' OR name IS NULL OR energy_kcal = 0)", // phpcs:ignore
				'Aam Achar (raw mango pickle)', $slug
			) );
		}
		update_option( 'fcc_seed_version', 106 );
	}

	/** Seed v107: Add page_content column for custom food page content. */
	public static function seed_v107(): void {
		if ( (int) get_option( 'fcc_seed_version', 0 ) >= 107 ) { return; }
		global $wpdb;
		$t    = $wpdb->prefix . 'fcc_foods';
		$cols = $wpdb->get_col( "SHOW COLUMNS FROM {$t}" ); // phpcs:ignore
		if ( ! in_array( 'page_content', $cols, true ) ) {
			$wpdb->query( "ALTER TABLE {$t} ADD COLUMN page_content text DEFAULT NULL AFTER is_active" ); // phpcs:ignore
		}
		update_option( 'fcc_seed_version', 107 );
	}

	public static function seed_v108(): void {
		if ( (int) get_option( 'fcc_seed_version', 0 ) >= 108 ) { return; }
		$all = Settings::get_all();
		$all['appearance']['chart_protein_colour'] = '#148B43';
		$all['appearance']['chart_carbs_colour']   = '#38C269';
		$all['appearance']['chart_fat_colour']     = '#159A4C';
		$all['appearance']['chart_other_colour']   = '#2D9A54';
		Settings::save( $all );
		update_option( 'fcc_seed_version', 108 );
	}
}
